import React, { useState } from 'react';
import { shapeDefinitions, defaultShape } from './shapes';
import Canvas from './components/Canvas';
import Sidebar from './components/Sidebar';
import CodePreview from './components/CodePreview';
import Toolbar from './components/Toolbar';
import BottomBar from './components/BottomBar';
import './styles/App.css';

const App = () => {
  const [figures, setFigures] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#000000');
  const [lineWidth, setLineWidth] = useState(2);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const handleMouseMove = (e) => {
    const canvas = e.target;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left - canvas.width / 2;
    const y = canvas.height / 2 - (e.clientY - rect.top);
    setMousePos({ x, y });
  };

  const handleShapeSelect = (shape) => {
    setSelectedShape(shape);
    setShapeParams({});
  };

  const handleParamChange = (param, value) => {
    setShapeParams(prev => ({
      ...prev,
      [param]: Number(value)
    }));
  };

  const handleDraw = () => {
    if (selectedShape === defaultShape) return;

    const newFigure = {
      type: selectedShape,
      params: shapeParams,
      color,
      lineWidth
    };

    const newFigures = [...figures, newFigure];
    setFigures(newFigures);
    setHistory([...history.slice(0, historyIndex + 1), newFigures]);
    setHistoryIndex(historyIndex + 1);
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      setHistoryIndex(historyIndex - 1);
      setFigures(history[historyIndex - 1]);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      setHistoryIndex(historyIndex + 1);
      setFigures(history[historyIndex + 1]);
    }
  };

  const handleDelete = () => {
    const newFigures = figures.filter((_, index) => index !== figures.length - 1);
    setFigures(newFigures);
    setHistory([...history.slice(0, historyIndex + 1), newFigures]);
    setHistoryIndex(historyIndex + 1);
  };

  return (
    <div className="app-container">
      <Toolbar
        onUndo={handleUndo}
        onRedo={handleRedo}
        onDelete={handleDelete}
      />

      <div className="app-body">
        <Sidebar
          selectedShape={selectedShape}
          onShapeSelect={handleShapeSelect}
          shapeParams={shapeParams}
          onParamChange={handleParamChange}
          color={color}
          onColorChange={setColor}
          lineWidth={lineWidth}
          onLineWidthChange={setLineWidth}
          mousePos={mousePos}
        />

        <div className="main-content-area">
          <div className="canvas-code-container">
            <div className="canvas-column">
              <Canvas
                figures={figures}
                onMouseMove={handleMouseMove}
              />
            </div>
            <CodePreview figures={figures} />
          </div>
        </div>
      </div>

      <BottomBar
        onDraw={handleDraw}
        onUndo={handleUndo}
        onRedo={handleRedo}
        onClear={handleDelete}
      />
    </div>
  );
};

export default App;
